from collections import defaultdict

class Solution(object):
    def countCompleteComponents(self, n, edges):
        adj = defaultdict(set)
        for u, v in edges:
            adj[u].add(v)
            adj[v].add(u)
        visited = [False] * n
        ans = 0
        for start in range(n):
            if visited[start]:
                continue
            # BFS to find component
            comp = []
            queue = [start]
            visited[start] = True
            while queue:
                nxt = []
                for u in queue:
                    comp.append(u)
                    for v in adj[u]:
                        if not visited[v]:
                            visited[v] = True
                            nxt.append(v)
                queue = nxt
            m_comp = len(comp)
            e_comp = sum(len(adj[u]) for u in comp) // 2
            if e_comp == m_comp * (m_comp - 1) // 2:
                ans += 1
        return ans
